function solve(points: number[][]): number {
    const n = points.length;
    const slopeMap: Map<string, number[]> = new Map();

    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const [x1, y1] = points[i];
            const [x2, y2] = points[j];
            let slope: string;

            if (x1 === x2) {
                slope = "inf"; // vertical line
            } else {
                slope = (y2 - y1).toString() + "/" + (x2 - x1).toString();
            }

            if (!slopeMap.has(slope)) {
                slopeMap.set(slope, []);
            }
            slopeMap.get(slope)!.push(i);
        }
    }

    let count = 0;

    for (const [slope, indices] of slopeMap.entries()) {
        if (indices.length < 2) continue;

        for (let i = 0; i < indices.length; i++) {
            for (let j = i + 1; j < indices.length; j++) {
                const p1 = indices[i];
                const p2 = indices[j];

                const [x1, y1] = points[p1];
                const [x2, y2] = points[p2];

                // Find pairs of points that form a line with the same slope
                for (let k = 0; k < indices.length; k++) {
                    if (k === i || k === j) continue;
                    const p3 = indices[k];

                    const [x3, y3] = points[p3];

                    // Check if the line between p1 and p3 has the same slope
                    let slope3: string;
                    if (x1 === x3) {
                        slope3 = "inf";
                    } else {
                        slope3 = (y3 - y1).toString() + "/" + (x3 - x1).toString();
                    }

                    if (slope3 === slope) {
                        // Check if the line between p2 and p3 has the same slope
                        let slope4: string;
                        if (x2 === x3) {
                            slope4 = "inf";
                        } else {
                            slope4 = (y3 - y2).toString() + "/" + (x3 - x2).toString();
                        }

                        if (slope4 === slope) {
                            // Check if the lines are not the same (not overlapping)
                            if (p1 !== p3 && p2 !== p3) {
                                count++;
                            }
                        }
                    }
                }
            }
        }
    }

    return count / 2; // Each trapezoid is counted twice
}

